// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	placeholders := make([]string, len(usernames))
	for i := range usernames {
		placeholders[i] = "?"
	}

	// We use aliases that match the struct field names (snake_case to CamelCase conversion)
	sql := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, 
		       COUNT(*) as total_actions, 
		       SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
		       AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) AND a.created_at BETWEEN ? AND ?`, strings.Join(placeholders, ","))

	params := make([]interface{}, 0)
	for _, u := range usernames {
		params = append(params, u)
	}
	params = append(params, startDate, endDate)

	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	sql += " GROUP BY u.display_name, a.action_type"

	var reports []UserActivitySummary
	_, err := o.Raw(sql, params...).QueryRows(&reports)
	if err != nil {
		return nil, err
	}

	if reports == nil {
		return []UserActivitySummary{}, nil
	}

	return reports, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	var col string
	switch groupByField {
	case "department":
		col = "u.department"
	case "role":
		col = "u.role"
	case "display_name":
		col = "u.display_name"
	default:
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	placeholders := make([]string, len(departments))
	for i := range departments {
		placeholders[i] = "?"
	}

	sql := fmt.Sprintf(`
		SELECT %s AS group_value, 
		       COUNT(DISTINCT u.id) AS user_count, 
		       COUNT(a.id) AS total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY %s`, col, strings.Join(placeholders, ","), col)

	params := make([]interface{}, 0)
	for _, d := range departments {
		params = append(params, d)
	}

	var rawResults []struct {
		GroupValue      string `orm:"column(group_value)"`
		UserCount       int    `orm:"column(user_count)"`
		TotalActivities int    `orm:"column(total_activities)"`
	}

	_, err := o.Raw(sql, params...).QueryRows(&rawResults)
	if err != nil {
		return nil, err
	}

	results := make([]map[string]interface{}, len(rawResults))
	for i, v := range rawResults {
		results[i] = map[string]interface{}{
			"group_value":      v.GroupValue,
			"user_count":       v.UserCount,
			"total_activities": v.TotalActivities,
		}
	}

	return results, nil
}

