	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}
	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build placeholders for the IN clause
	placeholders := make([]string, len(usernames))
	for i := range usernames {
		placeholders[i] = "?"
	}

	// Construct SQL query
	// Using total_actions alias to match TotalActions struct field
	sql := `SELECT u.display_name, a.action_type, COUNT(*) as total_actions, 
                   SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
                   AVG(a.duration_ms) as avg_duration
            FROM user_activity a 
            JOIN user_profile u ON a.user_id = u.id
            WHERE u.username IN (` + strings.Join(placeholders, ",") + `)`

	params := make([]interface{}, 0, len(usernames)+3)
	for _, u := range usernames {
		params = append(params, u)
	}

	if actionTypeFilter != "" {
		sql += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	sql += " AND a.created_at BETWEEN ? AND ? GROUP BY u.display_name, a.action_type"
	params = append(params, startDate, endDate)

	var reports []UserActivitySummary
	_, err := o.Raw(sql, params...).QueryRows(&reports)
	if err != nil {
		return nil, err
	}

	return reports, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField to prevent SQL injection
	var col string
	switch groupByField {
	case "department", "role", "display_name":
		col = groupByField
	default:
		return []map[string]interface{}{}, nil
	}

	placeholders := make([]string, len(departments))
	for i := range departments {
		placeholders[i] = "?"
	}

	// Construct SQL query with dynamic grouping
	sql := fmt.Sprintf(`SELECT u.%s AS group_value, COUNT(DISTINCT u.id) AS user_count, COUNT(a.id) AS total_activities 
                        FROM user_profile u 
                        LEFT JOIN user_activity a ON u.id = a.user_id 
                        WHERE u.department IN (%s) 
                        GROUP BY u.%s`, col, strings.Join(placeholders, ","), col)

	params := make([]interface{}, len(departments))
	for i, d := range departments {
		params[i] = d
	}

	var maps []orm.Params
	_, err := o.Raw(sql, params...).Values(&maps)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params (which is []map[string]string) to []map[string]interface{}
	results := make([]map[string]interface{}, 0, len(maps))
	for _, m := range maps {
		row := make(map[string]interface{})
		for k, v := range m {
			row[k] = v
		}
		results = append(results, row)
	}

	return results, nil
}

