type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Prepare placeholders for the IN clause
	placeholders := make([]string, len(usernames))
	params := make([]interface{}, 0, len(usernames)+3)
	for i, name := range usernames {
		placeholders[i] = "?"
		params = append(params, name)
	}

	// Build the SQL query with aliases matching the UserActivitySummary struct fields
	sql := "SELECT u.display_name, a.action_type, " +
		"COUNT(*) AS total_actions, " +
		"SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count, " +
		"AVG(a.duration_ms) AS avg_duration " +
		"FROM user_activity a JOIN user_profile u ON a.user_id = u.id " +
		"WHERE u.username IN (" + strings.Join(placeholders, ",") + ") "

	if actionTypeFilter != "" {
		sql += "AND a.action_type = ? "
		params = append(params, actionTypeFilter)
	}

	sql += "AND a.created_at BETWEEN ? AND ? "
	params = append(params, startDate, endDate)

	sql += "GROUP BY u.display_name, a.action_type"

	var reports []UserActivitySummary
	_, err := o.Raw(sql, params...).QueryRows(&reports)
	if err != nil {
		return nil, err
	}

	return reports, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField to prevent SQL injection since it's used directly in the query string
	var col string
	switch groupByField {
	case "department", "role", "display_name":
		col = groupByField
	default:
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Prepare placeholders for the IN clause
	placeholders := make([]string, len(departments))
	params := make([]interface{}, 0, len(departments))
	for i, dept := range departments {
		placeholders[i] = "?"
		params = append(params, dept)
	}

	// Build the dynamic SQL query
	sql := fmt.Sprintf("SELECT u.%s AS group_value, COUNT(DISTINCT u.id) AS user_count, COUNT(a.id) AS total_activities "+
		"FROM user_profile u LEFT JOIN user_activity a ON u.id = a.user_id "+
		"WHERE u.department IN (%s) "+
		"GROUP BY u.%s", col, strings.Join(placeholders, ","), col)

	var maps []orm.Params
	_, err := o.Raw(sql, params...).Values(&maps)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	result := make([]map[string]interface{}, len(maps))
	for i, m := range maps {
		result[i] = m
	}

	return result, nil
}

